# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import psycopg2
from psycopg2 import sql

def connect_to_db():
    conn = None
    try:
        conn = psycopg2.connect(host="localhost", database="document_management", user="postgres", password="password")  # Adjust these details as per your database setup
    except Exception as error:
        print("Error while connecting to PostgreSQL", error)
    return conn

def check_permission(user, file):
    conn = connect_to_db()
    if not conn:
        return False  # Return false if connection is unsuccessful
    
    cur = conn.cursor()
    query = sql.SQL("SELECT * FROM permissions WHERE user=%s AND file=%s")  # Assuming a table 'permissions' with columns 'user', 'file', and 'access_level'
    cur.execute(query, (user, file))
    
    result = cur.fetchone()
    if not result:
        return False

    access_level = result[2]  # Assuming the third column contains the access level
    if access_level == 'read':   # Check for read permission
        return True
    else:
        return False

def open_file(user, file):
    has_permission = check_permission(user, file)
    
    if not has_permission:
        print("Access denied")
        return None
        
    try:
        with open(file, 'r') as f:  # Open the file in read mode
            content = f.read()      # Read the contents of the file
        return content             # Return the file's contents
    except Exception as e:          # Catch any exception that may occur when trying to open or read the file
        print("Error while opening/reading file", e)